from flask import Flask, request
import logging

app = Flask(__name__)

@app.route('/log', methods=['POST'])
def log():
    message = request.json.get('message', '')
    service = request.json.get('service', '')

    # adjust the string format according to your need
    log_message = "Service Name: {}, Log Message: {}".format(service, message)
    app.logger.warning(log_message)

    return {"status": "Log processed"}, 200

if __name__ == "__main__":
    logging.basicConfig(filename='application_logs.log', level=logging.WARNING)
    app.run(host='0.0.0.0', port=5000, debug=True)